mapper.select:
SELECT r.id AS id, r.form_id AS form_id, f.title AS form_title, f.slug AS form_slug, r.reason AS reason, r.detail AS detail, r.status AS status, r.reporter_user_id AS reporter_user_id, r.handled_by AS handled_by, r.handled_at AS handled_at, (SELECT COUNT(*) FROM form_reports fr WHERE fr.form_id = r.form_id AND fr.status = 'PENDING') AS pending_count_for_form, r.created_at AS created_at FROM form_reports r JOIN forms f ON f.id = r.form_id
r.status = #{status}
ORDER BY r.created_at DESC, r.id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE form_reports
SET status = #{status}, handled_by = #{handledBy}, handled_at = #{handledAt}
WHERE id = #{id}
